import type { ReactNode } from 'react';
import React from 'react';
import { isFragment } from 'react-is';

// type ReactFlatNode = Exclude<ReactNode, null | undefined>;

export function toFlatArray(children: React.ReactNode, options: { keepEmpty?: boolean } = {}): ReactNode[] {
  const { keepEmpty = false } = options;
  let ret: ReactNode[] = [];

  React.Children.forEach(children, child => {
    if ((child === undefined || child === null) && !keepEmpty) {
      return;
    }

    if (Array.isArray(child)) {
      ret = ret.concat(toFlatArray(child));
    } else if (isFragment(child) && child.props) {
      ret = ret.concat(toFlatArray(child.props.children));
    } else {
      ret.push(child);
    }
  });

  return ret;
}
